class Solution:
    def bestTower(self, towers, center, radius):
        cx, cy = center
        candidates = []
        for x, y, q in towers:
            dist = abs(x - cx) + abs(y - cy)
            if dist <= radius:
                candidates.append((-q, x, y))
        if not candidates:
            return [-1, -1]
        candidates.sort()
        _, bx, by = candidates[0]
        return [bx, by]

