class Solution:
    def bestTower(self, towers, center, radius):
        cx, cy = center
        best_q = None
        best_x = best_y = -1
        for x, y, q in towers:
            dist = abs(x - cx) + abs(y - cy)
            if dist > radius:
                continue
            if best_q is None or q > best_q or (q == best_q and (x, y) < (best_x, best_y)):
                best_q = q
                best_x, best_y = x, y
        if best_q is None:
            return [-1, -1]
        return [best_x, best_y]

