var bestTower = function(towers, center, radius) {
    const [cx, cy] = center;
    let bestQ = null, bestX = -1, bestY = -1;
    for (const [x, y, q] of towers) {
        const dist = Math.abs(x - cx) + Math.abs(y - cy);
        if (dist > radius) continue;
        if (bestQ === null || q > bestQ || (q === bestQ && (x < bestX || (x === bestX && y < bestY)))) {
            bestQ = q;
            bestX = x;
            bestY = y;
        }
    }
    if (bestQ === null) return [-1, -1];
    return [bestX, bestY];
};
